INSERT INTO `receipts` VALUES (1,1,NULL,NULL,NULL,'2026-05-13 20:44:13','2026-05-13 20:44:13'),(2,2,'Eu _______________________________________________, inscrito (a) sob CPF/CNPJ número __________________________________, me responsabilizo por eventuais perdas e/ou danos de arquivos, fotos, agenda, ou quaisquer outros dados armazenados no HD, SSD, cartão de memória, ou memória interna do meu equipamento, inclusive películas ou adesivos, capas e demais acessórios, ficando a Mega System Informática isenta de qualquer responsabilidade. É obrigatória a apresentação desta Ordem de Serviço (O.S.) no ato da retirada para que o mesmo seja liberado pela empresa! Caso o aparelho não seja retirado em até 90 dias, a contar da presente data, tal fato será considerado como abandono, estando a empresa apta a descartá-lo. O (A) cliente declara e reconhece que todas as informações aqui fornecidas são verdadeiras e que entendeu e aceitou todos os termos desta Ordem de Serviço.','De acordo com o Código de Defesa do Consumidor (Lei n°.8.078/90, seção IV, Art.26) o cliente tem o direito de solicitar a garantia pelo serviço executado em 30 (trinta) dias, tratando-se de serviços e de produtos não duráveis (relacionado a sistema); 90 (noventa) dias, tratando-se de fornecimento de serviço e de produtos duráveis (relacionado a peças).','Equipamento analisado preliminarmente. Segue orçamento inicial para reparo conforme diagnóstico técnico apresentado nesta O.S. O serviço será executado somente mediante aprovação do cliente. Valores e prazo podem sofrer alterações caso sejam identificadas necessidades adicionais durante o reparo.','2026-05-16 23:41:05','2026-05-18 17:48:11');
/*!40000 ALTER TABLE `receipts` ENABLE KEYS */;
UNLOCK TABLES;

